public Complex tanh() {
    if (isNaN || Double.isNaN(real) || Double.isNaN(imaginary)) {
        return NaN;
    }
    double real2 = 2.0 * real;
    double imaginary2 = 2.0 * imaginary;
    double sinhReal2 = FastMath.sinh(real2);
    double coshReal2 = FastMath.cosh(real2);
    double cosImaginary2 = FastMath.cos(imaginary2);
    double sinImaginary2 = FastMath.sin(imaginary2);
    double d = coshReal2 + cosImaginary2;

    if (Double.isInfinite(d)) {
        // Handle infinite denominator cases
        if (Double.isInfinite(sinhReal2)) {
            return createComplex(FastMath.copySign(1.0, real), 0.0);
        } else {
            return NaN;
        }
    } else if (Double.isInfinite(real2) && Double.isFinite(imaginary2)) {
        // Handle cases where real part is infinite and imaginary part is finite
        return createComplex(FastMath.copySign(1.0, real), 0.0);
    } else if (Double.isInfinite(imaginary2) && Double.isFinite(real2)) {
        // Handle cases where imaginary part is infinite and real part is finite
        return NaN;
    }

    return createComplex(sinhReal2 / d, sinImaginary2 / d);
}

public Complex tanh() {
    if (isNaN || Double.isNaN(real) || Double.isNaN(imaginary)) {
        return NaN;
    }
    double real2 = 2.0 * real;
    double imaginary2 = 2.0 * imaginary;
    double cosh2a = FastMath.cosh(real2);
    double cos2b = FastMath.cos(imaginary2);
    double sinh2a = FastMath.sinh(real2);
    double sin2b = FastMath.sin(imaginary2);

    if (Double.isInfinite(cosh2a) && Double.isFinite(cos2b)) {
        return createComplex(FastMath.signum(real) * 1.0, 0.0);
    } else if (Double.isInfinite(cos2b) && Double.isFinite(cosh2a)) {
        return createComplex(0.0, FastMath.signum(imaginary) * Double.POSITIVE_INFINITY);
    } else if (Double.isInfinite(cosh2a) && Double.isInfinite(cos2b)) {
        return NaN;
    }

    double d = cosh2a + cos2b;
    if (d == 0.0) {
        return NaN;
    }

    return createComplex(sinh2a / d,
                         sin2b / d);
}

public Complex tanh() {
    if (isNaN || Double.isInfinite(real) && Double.isInfinite(imaginary)) {
        return NaN;
    }
    double real2 = 2.0 * real;
    double imaginary2 = 2.0 * imaginary;
    double cosh2a = FastMath.cosh(real2);
    double cos2b = FastMath.cos(imaginary2);
    double d = cosh2a + cos2b;

    if (Double.isInfinite(real)) {
        return createComplex(FastMath.signum(real), 0.0);
    }
    if (Double.isInfinite(imaginary)) {
        if (imaginary2 % (2 * Math.PI) == 0) {
            return createComplex(0.0, FastMath.signum(imaginary) * Double.POSITIVE_INFINITY);
        } else {
            return NaN;
        }
    }
    if (Double.isInfinite(d)) {
        return createComplex(FastMath.signum(real), 0.0);
    }

    return createComplex(FastMath.sinh(real2) / d,
                         FastMath.sin(imaginary2) / d);
}

